        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _set_process_priority(self, pid: int) -> None:
        priority = self.process_priority

        if priority not in (
            "low",
            "below_normal",
            "normal",
            "above_normal",
            "high",
        ):
            return

        try:
            if WIN:
                import ctypes

                priority_classes = {
                    "low": 0x40,
                    "below_normal": 0x4000,
                    "normal": 0x20,
                    "above_normal": 0x8000,
                    "high": 0x80,
