                        )
                    finally:
                        ctypes.windll.kernel32.CloseHandle(handle)  # type: ignore
            else:
                niceness = {
                    "low": 19,
                    "below_normal": 10,
                    "normal": 0,
                    "above_normal": -5,
                    "high": -10,
                }[priority]
                os.setpriority(os.PRIO_PROCESS, pid, niceness)
        except Exception:
            pass

